final class KeychainService {
    static let shared = KeychainService()
    private init() {}

    func save(data: Data, for key: String) throws {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecValueData as String: data,
            kSecAttrAccessible as String: kSecAttrAccessibleAfterFirstUnlockThisDeviceOnly
        ]
        SecItemDelete(query as CFDictionary)
        let status = SecItemAdd(query as CFDictionary, nil)
        guard status == errSecSuccess else { throw WalletError.keychainSaveFailed }
    }

    func read(for key: String) throws -> Data {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        var result: CFTypeRef?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        guard status == errSecSuccess, let data = result as? Data else { throw WalletError.keychainReadFailed }
        return data
    }

    func delete(for key: String) throws {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key
        ]
        let status = SecItemDelete(query as CFDictionary)
        guard status == errSecSuccess || status == errSecItemNotFound else { throw WalletError.keychainDeleteFailed }
    }
}

final class WalletManager: ObservableObject {
    @Published var address: String = ""
    @Published var status: String = "No wallet loaded"
    @Published var lastSignature: String = ""
    @Published var lastResponse: String = ""

    private let privateKeyKey = "crypto_wallet_private_key"

    init() {
        loadWallet()
    }

    func createWallet() {
        let privateKey = P256.Signing.PrivateKey()
        let raw = privateKey.rawRepresentation
        do {
            try KeychainService.shared.save(data: raw, for: privateKeyKey)
            address = Self.deriveAddress(from: raw)
            status = "Wallet created"
        } catch {
            status = error.localizedDescription
        }
    }

    func loadWallet() {
        do {
            let raw = try KeychainService.shared.read(for: privateKeyKey)
            address = Self.deriveAddress(from: raw)
            status = "Wallet loaded"
        } catch {
            address = ""
            status = "No wallet loaded"
        }
    }

    func deleteWallet() {
        do {
            try KeychainService.shared.delete(for: privateKeyKey)
            address = ""
            status = "Wallet deleted"
        } catch {
            status = error.localizedDescription
        }
    }

    func sign(transaction: WalletTransaction) {
        do {
            let raw = try KeychainService.shared.read(for: privateKeyKey)
            guard let privateKey = try? P256.Signing.PrivateKey(rawRepresentation: raw) else {
                throw WalletError.invalidPrivateKey
            }
            let payload = try JSONEncoder().encode(transaction)
            let signature = try privateKey.signature(for: payload)
            lastSignature = signature.derRepresentation.base64EncodedString()
            status = "Transaction signed"
        } catch {
            status = error.localizedDescription
        }
    }

    func send(transaction: WalletTransaction) {
        do {
            let raw = try KeychainService.shared.read(for: privateKeyKey)
            guard let privateKey = try? P256.Signing.PrivateKey(rawRepresentation: raw) else {
                throw WalletError.invalidPrivateKey
            }
            let payload = try JSONEncoder().encode(transaction)
            let signature = try privateKey.signature(for: payload)
            let signed = SignedTransaction(rawTransaction: payload, signature: signature.derRepresentation)

            guard let url = URL(string: "https://example.com/api/transactions") else { throw WalletError.networkError }
            var request = URLRequest(url: url)
            request.httpMethod = "POST"
            request.setValue("application/json", forHTTPHeaderField: "Content-Type")
            request.httpBody = try JSONEncoder().encode([
                "rawTransaction": signed.rawTransaction.base64EncodedString(),
                "signature": signed.signature.base64EncodedString()
            ])

            URLSession.shared.dataTask(with: request) { [weak self] data, response, error in
                DispatchQueue.main.async {
                    if let error = error {
                        self?.lastResponse = error.localizedDescription
                        return
                    }
                    let responseString = data.flatMap { String(data: $0, encoding: .utf8) } ?? "No response body"
                    self?.lastResponse = responseString
                }
            }.resume()

            lastSignature = signature.derRepresentation.base64EncodedString()
            status = "Transaction sent"
        } catch {
            status = error.localizedDescription
        }
    }

    private static func deriveAddress(from privateKeyRaw: Data) -> String {
        let digest = SHA256.hash(data: privateKeyRaw)
        return "0x" + digest.compactMap { String(format: "%02x", $0) }.joined()
    }
}

