    private static func hexData(from string: String) -> Data {
        let cleaned = string.replacingOccurrences(of: "0x", with: "")
        var data = Data()
        var index = cleaned.startIndex
        while index < cleaned.endIndex {
            let next = cleaned.index(index, offsetBy: 2, limitedBy: cleaned.endIndex) ?? cleaned.endIndex
            let byteString = cleaned[index..<next]
            if let byte = UInt8(byteString, radix: 16) {
